const fs = require('fs');
const OUTLET_PATH = '/Users/sarahevans_zen/.openclaw/workspace/projects/asksarah-ai/agi-outlet-list.json';

let outletData;
try {
  outletData = JSON.parse(fs.readFileSync(OUTLET_PATH, 'utf8'));
} catch(e) {
  throw new Error('Failed to load outlet list: ' + e.message);
}

const outlets = outletData.outlets
  .filter(o => o.rss !== null && o.rss !== undefined)
  .map(o => ({
    outlet_id: o.id,
    outlet_name: o.name,
    rss_url: o.rss_ai || o.rss,
    fallback_rss: o.rss,
    api_type: Array.isArray(o.api) ? o.api.join(',') : (o.api || 'rss'),
    tier: o.tier,
    region: o.region || 'Global',
    topics: (o.topics || []).join(', '),
    frequency: o.frequency || 'unknown',
    fetch_started: new Date().toISOString()
  }));

console.log(`[AGI Monitor] Loaded ${outlets.length} outlets from ${outletData.outlets.length} total`);

return outlets;

const item = $input.first();
const { outlet_id, outlet_name, tier, rss_url } = item.json;

function extractTag(text, tag) {
  const cdataRe = new RegExp('<' + tag + '[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]></' + tag + '>', 'i');
  const m = text.match(cdataRe);
  if (m) return m[1].trim();
  const tagRe = new RegExp('<' + tag + '[^>]*>([\\s\\S]*?)</' + tag + '>', 'i');
  const m2 = text.match(tagRe);
  return m2 ? m2[1].trim() : null;
}

function extractLink(text) {
  const atomHref = text.match(/<link[^>]+href="([^"]+)"/i);
  if (atomHref) return atomHref[1];
  const rssLink = text.match(/<link[^>]*>\s*([^<]+)\s*<\/link>/i);
  if (rssLink) return rssLink[1].trim();
  return null;
}

function cleanHtml(t) {
  if (!t) return '';
  return t.replace(/<[^>]+>/g,'')
    .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')
    .replace(/&quot;/g,'"').replace(/&#039;/g,"'").replace(/&apos;/g,"'")
    .replace(/\s+/g,' ').trim();
}

// Get response body
let xml = '';
try {
  if (item.json.data !== undefined) {
    xml = typeof item.json.data === 'string' ? item.json.data : JSON.stringify(item.json.data);
  } else if (item.json.body !== undefined) {
    xml = item.json.body;
  } else if (item.json.error) {
    return [{ json: { outlet_id, outlet_name, tier, articles: [], article_count: 0, fetch_failed: true, error: item.json.error } }];
  }
} catch(e) {
  return [{ json: { outlet_id, outlet_name, tier, articles: [], article_count: 0, fetch_failed: true, error: e.message } }];
}

if (!xml || xml.length < 50) {
  return [{ json: { outlet_id, outlet_name, tier, articles: [], article_count: 0, fetch_failed: true, error: 'Empty response' } }];
}

// Time cutoff: 48h for tier 1-2, 7d for tier 3-6
const cutoffHours = tier <= 2 ? 48 : 168;
const cutoff = new Date(Date.now() - cutoffHours * 3600000);

const itemPattern = /<item[\s>][\s\S]*?<\/item>|<entry[\s>][\s\S]*?<\/entry>/gi;
const matches = xml.match(itemPattern) || [];

const articles = [];
for (const itemXml of matches.slice(0, 30)) {
  const title = extractTag(itemXml, 'title');
  const link = extractLink(itemXml);
  if (!title || !link) continue;

  const pubRaw = extractTag(itemXml, 'pubDate') ||
                 extractTag(itemXml, 'published') ||
                 extractTag(itemXml, 'updated') ||
                 extractTag(itemXml, 'dc:date');

  let articleDate;
  try {
    articleDate = pubRaw ? new Date(pubRaw) : new Date();
    if (isNaN(articleDate.getTime())) articleDate = new Date();
  } catch(_) { articleDate = new Date(); }

  if (articleDate < cutoff) continue;

  const description = extractTag(itemXml, 'description') || extractTag(itemXml, 'summary') || '';
  const author = extractTag(itemXml, 'author') || extractTag(itemXml, 'dc:creator') || '';

  articles.push({
    outlet_id,
    outlet_name,
    tier,
    headline: cleanHtml(title).substring(0, 300),
    url: link.trim(),
    date: articleDate.toISOString().split('T')[0],
    timestamp: articleDate.toISOString(),
    description: cleanHtml(description).substring(0, 500),
    author: cleanHtml(author).substring(0, 100)
  });
}

console.log(`[${outlet_id}] Parsed ${articles.length} articles from ${matches.length} feed items`);
return [{ json: { outlet_id, outlet_name, tier, articles, article_count: articles.length, fetch_failed: false } }];

const crypto = require('crypto');
const items = $input.all();

const allArticles = [];
let failedOutlets = 0;
let successOutlets = 0;

for (const item of items) {
  const d = item.json;
  if (d.fetch_failed) { failedOutlets++; continue; }
  successOutlets++;
  allArticles.push(...(d.articles || []));
}

// SHA256(normalized_headline + date) → story_id
const storyMap = {};

for (const art of allArticles) {
  const normalized = art.headline.toLowerCase().replace(/[^a-z0-9 ]/g, '').replace(/\s+/g, ' ').trim();
  const raw = normalized + '::' + art.date;
  const story_id = crypto.createHash('sha256').update(raw).digest('hex').substring(0, 16);

  if (!storyMap[story_id]) {
    storyMap[story_id] = {
      story_id,
      headline: art.headline,
      representative_url: art.url,
      date: art.date,
      timestamp: art.timestamp,
      description: art.description,
      sources: [],
      source_ids: new Set(),
      min_tier: art.tier
    };
  }

  const s = storyMap[story_id];
  if (!s.source_ids.has(art.outlet_id)) {
    s.source_ids.add(art.outlet_id);
    s.sources.push({ outlet_id: art.outlet_id, outlet_name: art.outlet_name, url: art.url, tier: art.tier });
    if (art.tier < s.min_tier) s.min_tier = art.tier;
  }
}

const stories = Object.values(storyMap).map(s => ({
  ...s,
  source_ids: Array.from(s.source_ids),
  source_count: s.sources.length,
  top_voices: [],
  amplifiers: [],
  twitter_checked: false,
  twitter_amplifiers_found: 0
})).sort((a,b) => b.source_count - a.source_count).slice(0, 300);

const stats = {
  run_id: crypto.randomBytes(4).toString('hex'),
  timestamp: new Date().toISOString(),
  outlets_checked: items.length,
  outlets_success: successOutlets,
  outlets_failed: failedOutlets,
  total_articles: allArticles.length,
  unique_stories: stories.length,
  dedupe_rate: allArticles.length > 0
    ? ((1 - stories.length / allArticles.length) * 100).toFixed(1) + '%'
    : '0%'
};

console.log('[AGI Monitor] Dedup stats:', JSON.stringify(stats));

// Emit stats item + story items
const output = [{ json: { _type: 'stats', ...stats } }];
for (const s of stories) {
  output.push({ json: { _type: 'story', ...s } });
}
return output;

