const TWITTER_BEARER = $env.TWITTER_BEARER_TOKEN || '';
const TWITTER_ENABLED = TWITTER_BEARER.length > 30;
const TWITTER_LIMIT  = 40;   // Max Twitter API calls per run (rate limit)
const DELAY_MS = 1100;        // ms between Twitter calls
const MIN_SOURCES_FOR_TWITTER = 2; // Only check Twitter for 2+ source stories

const sleep = ms => new Promise(r => setTimeout(r, ms));

const stories = $input.all().map(i => i.json);
let twitterCalls = 0;

const processed = [];

for (let idx = 0; idx < stories.length; idx++) {
  const story = { ...stories[idx] };
  let amplifiers = [];

  if (TWITTER_ENABLED && twitterCalls < TWITTER_LIMIT && story.source_count >= MIN_SOURCES_FOR_TWITTER) {
    try {
      await sleep(DELAY_MS);

      // Build search query
      const safeHeadline = story.headline.substring(0, 60).replace(/["\']/g, '').trim();
      const queryParts = [`"${safeHeadline}"`, '-is:retweet', 'lang:en'].join(' ');
      const params = new URLSearchParams({
        query: queryParts,
        max_results: '20',
        expansions: 'author_id',
        'user.fields': 'public_metrics,username,name',
        'tweet.fields': 'public_metrics,created_at,author_id'
      });

      const resp = await fetch(`https://api.twitter.com/2/tweets/search/recent?${params}`, {
        headers: { Authorization: `Bearer ${TWITTER_BEARER}` }
      });

      twitterCalls++;

      if (resp.ok) {
        const tData = await resp.json();
        const usersById = {};
        for (const u of (tData.includes?.users || [])) usersById[u.id] = u;

        for (const tweet of (tData.data || [])) {
          const user = usersById[tweet.author_id];
          if (!user) continue;

          const likes     = tweet.public_metrics?.like_count || 0;
          const retweets  = tweet.public_metrics?.retweet_count || 0;
          const followers = user.public_metrics?.followers_count || 1;
          const handle    = (user.username || '').toLowerCase();

          const engagement_rate    = (likes + retweets) / Math.max(followers, 1);
          const weighted_reach     = Math.round(followers * engagement_rate);
          const known              = handleToVoice[handle];
          const accuracy_score     = known ? known.accuracy_score     : 0.50;
          const credibility_rating = known ? known.credibility_rating : 0.50;

          amplifiers.push({
            twitter_id:          tweet.author_id,
            username:            user.username,
            display_name:        known ? known.name : (user.name || user.username),
            followers,
            likes,
            retweets,
            engagement_rate:     Math.round(engagement_rate * 10000) / 10000,
            weighted_reach,
            accuracy_score,
            credibility_rating,
            weighted_credibility: Math.round(weighted_reach * credibility_rating),
            is_known_voice:      !!known,
            voice_id:            known ? known.voice_id : null
          });
        }
      } else if (resp.status === 429) {
        console.log('[Twitter] Rate limited — stopping Twitter calls for this run');
        twitterCalls = TWITTER_LIMIT; // Stop further calls
      } else {
        console.log(`[Twitter] HTTP ${resp.status} for story ${story.story_id}`);
      }
    } catch(err) {
      console.log('[Twitter] Error:', err.message);
    }
  }

  const top_voices = [...amplifiers]
    .sort((a,b) => b.weighted_credibility - a.weighted_credibility)
    .slice(0, 5);

  processed.push({
    ...story,
    amplifiers,
    top_voices,
    twitter_checked:         TWITTER_ENABLED && story.source_count >= MIN_SOURCES_FOR_TWITTER,
    twitter_amplifiers_found: amplifiers.length
  });
}

console.log(`[AGI Monitor] Twitter: ${twitterCalls} API calls, ${processed.length} stories scored`);
return processed.map(s => ({ json: s }));

const fs   = require('fs');
const path = require('path');

const stories = $input.all().map(i => i.json);
const today   = new Date().toISOString().split('T')[0];

const DASHBOARD_DIR = '/Users/sarahevans_zen/.openclaw/workspace/projects/asksarah-ai/data/dashboard-stories';
if (!fs.existsSync(DASHBOARD_DIR)) fs.mkdirSync(DASHBOARD_DIR, { recursive: true });

const dashboardOutput = {
  generated_at:   new Date().toISOString(),
  date:           today,
  total_stories:  stories.length,
  major_stories:  stories.filter(s => s.source_count >= 10).length,
  significant:    stories.filter(s => s.source_count >= 5 && s.source_count < 10).length,
  stories: stories.map(s => ({
    story_id:          s.story_id,
    headline:          s.headline,
    date:              s.date,
    timestamp:         s.timestamp,
    source_count:      s.source_count,
    sources:           s.sources,
    representative_url: s.representative_url,
    description:       s.description,
    top_voices:        (s.top_voices || []).map(v => ({
      username:             v.username,
      display_name:         v.display_name,
      followers:            v.followers,
      engagement_rate:      v.engagement_rate,
      weighted_credibility: v.weighted_credibility,
      accuracy_score:       v.accuracy_score,
      is_known_voice:       v.is_known_voice
    })),
    amplifiers_count:  (s.amplifiers || []).length,
    twitter_checked:   s.twitter_checked || false,
    alert_level:       s.source_count >= 10 ? 'major'
                     : s.source_count >= 5  ? 'significant'
                     : 'normal',
    min_tier:          s.min_tier
  }))
};

// Write dated file
const datedPath = path.join(DASHBOARD_DIR, `dashboard-stories-${today}.json`);
fs.writeFileSync(datedPath, JSON.stringify(dashboardOutput, null, 2));

// Write latest pointer
const latestPath = path.join(DASHBOARD_DIR, 'dashboard-stories-latest.json');
fs.writeFileSync(latestPath, JSON.stringify(dashboardOutput, null, 2));

console.log(`[AGI Monitor] Dashboard written: ${datedPath} (${stories.length} stories)`);

const majorStories = dashboardOutput.stories.filter(s => s.alert_level === 'major');
return [{ json: {
  success:      true,
  filepath:     datedPath,
  stories_count: stories.length,
  major_stories: majorStories,
  all_stories:  dashboardOutput.stories
} }];

const TELEGRAM_BOT_TOKEN = $env.TELEGRAM_BOT_TOKEN || '';
const TELEGRAM_CHAT_ID   = $env.TELEGRAM_CHAT_ID   || '8206233476';

const item        = $input.first().json;
const majorStories = item.major_stories || [];

if (!TELEGRAM_BOT_TOKEN || TELEGRAM_BOT_TOKEN.length < 10) {
  console.log('[Telegram] No bot token configured — skipping alerts');
  return [{ json: { alerts_sent: 0, reason: 'no_token' } }];
}
if (majorStories.length === 0) {
  console.log('[Telegram] No major stories (10+ sources) this run');
  return [{ json: { alerts_sent: 0, reason: 'no_major_stories' } }];
}

const sleep = ms => new Promise(r => setTimeout(r, ms));
let alertsSent = 0;

for (const story of majorStories) {
  const topNames = (story.top_voices || []).slice(0, 3).map(v => v.display_name).join(', ') || 'None tracked';
  const sourceList = (story.sources || []).slice(0, 5).map(s => s.outlet_name).join(', ');
  const moreStr = story.source_count > 5 ? ` +${story.source_count - 5} more` : '';

  const text = [
    `📰 *AGI Story Alert*`,
    ``,
    `*${story.headline.substring(0, 200).replace(/[*_[]()~`>#+=|{}.!-]/g, '\\$&')}*`,
    ``,
    `🔊 ${story.source_count} sources · Top: ${topNames}`,
    `🔗 ${story.representative_url}`,
    ``,
    `📡 Sources: ${sourceList}${moreStr}`
  ].join('\n');

  try {
    const resp = await fetch(`https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({
        chat_id:                  TELEGRAM_CHAT_ID,
        text,
        parse_mode:               'MarkdownV2',
        disable_web_page_preview: false
      })
    });
    if (resp.ok) { alertsSent++; }
    else { console.log('[Telegram] Send failed:', await resp.text()); }
    await sleep(500);
  } catch(e) {
    console.log('[Telegram] Error:', e.message);
  }
}

return [{ json: { alerts_sent: alertsSent, major_story_count: majorStories.length } }];

